export default class App extends Component {


  state = { listVisible: "" }
  search = (e) => { this.setState({ listVisible: e }) }


  render() {
    const search = (e) => { this.setState({ listVisible: e }) }
    const { listVisible } = this.state
    return (
      <div>
        <Router>
          <NAV search={this.search} />
          <Routes>
            <Route exact path="/" element={<MAIN listVisible={listVisible} tag={null} list={Post} />} />      {/*             MAIN             */}
            <Route path="/posts/:id_post" element={<POSTWINDOW list={Post} listTwo={PostLikes} />} />         {/*          POSTWINDOW          */}
            <Route path="/create-post" element={<CREATEWIND />} />                                            {/*          CREATEWIND          */}
            <Route path="/account" element={<ACCOUNT />} />                                                   {/*           ACCOUNT            */}
            <Route path="*" element={<h1 className="error">ERROR404</h1>} />                                  {/*            ERROR            */}
          </Routes>
        </Router>
      </div>
    )
  }
}
